import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Tag, Palette, Edit2, Target, Loader2 } from 'lucide-react';
import '../styles/Categorias.css';

const Categorias = () => {
  const [categorias, setCategorias] = useState([]);
  const [metasMes, setMetasMes] = useState([]); 
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedCat, setSelectedCat] = useState(null);
  
  const [mesAtual] = useState(new Date().getMonth() + 1);
  const [anoAtual] = useState(new Date().getFullYear());

  const [form, setForm] = useState({ nome: '', cor: '#4361ee', meta_valor: '' });

  useEffect(() => {
    buscarDados();
  }, [mesAtual, anoAtual]);

  async function buscarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: cats, error: catError } = await supabase
        .from('categorias')
        .select('*')
        .order('nome');
      if (catError) throw catError;

      const { data: mtd, error: metaError } = await supabase
        .from('metas')
        .select('*')
        .eq('mes_referencia', mesAtual)
        .eq('ano_referencia', anoAtual);
      if (metaError) throw metaError;

      setCategorias(cats || []);
      setMetasMes(mtd || []);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setLoading(false);
    }
  }

  const openModal = (cat = null) => {
    if (cat) {
      const metaExistente = metasMes.find(m => m.categoria_id === cat.id);
      
      setEditMode(true);
      setSelectedCat(cat);
      setForm({ 
        nome: cat.nome, 
        cor: cat.cor, 
        meta_valor: metaExistente ? metaExistente.valor_meta : '' 
      });
    } else {
      setEditMode(false);
      setSelectedCat(null);
      setForm({ nome: '', cor: '#4361ee', meta_valor: '' });
    }
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    try {
      const { data: { user } } = await supabase.auth.getUser();
      
      let categoriaId = selectedCat?.id;

      const catPayload = { 
        user_id: user.id, 
        nome: form.nome, 
        tipo: activeTab, 
        cor: form.cor
      };

      if (editMode && categoriaId) {
        await supabase.from('categorias').update(catPayload).eq('id', categoriaId);
      } else {
        const { data: newCat, error: insError } = await supabase
          .from('categorias')
          .insert([catPayload])
          .select().single();
        if (insError) throw insError;
        categoriaId = newCat.id;
      }

      if (form.meta_valor !== '') {
        const { error: metaError } = await supabase
          .from('metas')
          .upsert({
            user_id: user.id,
            categoria_id: categoriaId,
            valor_meta: parseFloat(form.meta_valor),
            tipo_meta: activeTab,
            mes_referencia: mesAtual,
            ano_referencia: anoAtual
          }, { onConflict: 'categoria_id, mes_referencia, ano_referencia' });
        
        if (metaError) throw metaError;
      }

      setShowModal(false);
      buscarDados();
    } catch (error) {
      alert("Erro ao salvar: " + error.message);
    }
  }

  async function excluirCategoria() {
    if (window.confirm(`Excluir permanentemente "${form.nome}"? Isso removerá as metas associadas.`)) {
      try {
        await supabase.from('categorias').delete().eq('id', selectedCat.id);
        setShowModal(false);
        buscarDados();
      } catch (error) {
        console.error("Erro ao excluir:", error);
      }
    }
  }

  const formatCurrency = (val) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);
  };

  const categoriasFiltradas = categorias.filter(c => c.tipo === activeTab);

  return (
    <div className="cat-page-wrapper">
      {/* 1. Botão FAB no topo para carregamento instantâneo */}
      <button className="cat-fab" onClick={() => openModal()} title="Nova Categoria">
        <Plus size={30} />
      </button>

      {/* 2. Modal Overlay ajustado para centralização */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="cat-modal" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>{editMode ? 'Editar Categoria' : 'Nova Categoria'}</h3>
              <button onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="cat-modal-form">
              <div className="cat-input-box">
                <label><Tag size={14}/> Nome da Categoria</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Alimentação, Lazer..."
                />
              </div>

              <div className="cat-input-box">
                <label><Target size={14}/> Meta para {new Intl.DateTimeFormat('pt-BR', {month: 'long'}).format(new Date())}</label>
                <div className="cat-money-input-wrapper">
                  <span className="prefix">R$</span>
                  <input 
                    type="number" step="0.01"
                    value={form.meta_valor} 
                    onChange={e => setForm({...form, meta_valor: e.target.value})} 
                    placeholder="0,00"
                  />
                </div>
              </div>
              
              <div className="cat-input-box">
                <label><Palette size={14}/> Cor</label>
                <div className="cat-color-picker-container">
                   <input type="color" className="cat-color-input" value={form.cor} onChange={e => setForm({...form, cor: e.target.value})} />
                   <input type="text" className="cat-hex-input" value={form.cor.toUpperCase()} onChange={e => setForm({...form, cor: e.target.value})} maxLength={7} />
                </div>
              </div>

              <div className="cat-modal-actions">
                {editMode && (
                  <button type="button" className="btn-cat-delete" onClick={excluirCategoria}>Excluir</button>
                )}
                <button type="submit" className="btn-cat-save">
                  {editMode ? 'Salvar Alterações' : 'Criar Categoria'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* 3. Conteúdo da página */}
      <header className="cat-header">
        <div className="cat-title-area">
          <h1>Categorias</h1>
          <p>Defina seus rótulos e orçamentos mensais</p>
        </div>
        
        <div className="cat-tab-container">
          <button className={activeTab === 'provento' ? 'active' : ''} onClick={() => setActiveTab('provento')}>Entradas</button>
          <button className={activeTab === 'despesa' ? 'active' : ''} onClick={() => setActiveTab('despesa')}>Saídas</button>
        </div>
      </header>

      <div className="cat-list-container">
        {loading ? (
          <div className="cat-status"><Loader2 className="spinner" /> Carregando categorias...</div>
        ) : categoriasFiltradas.length > 0 ? (
          categoriasFiltradas.map(cat => {
            const meta = metasMes.find(m => m.categoria_id === cat.id);
            return (
              <div key={cat.id} className="cat-item-row" onClick={() => openModal(cat)}>
                <div className="cat-item-main">
                  <div className="cat-status-dot" style={{ backgroundColor: cat.cor }}></div>
                  <div className="cat-info-text">
                    <span className="cat-item-name" style={{ color: cat.cor }}>{cat.nome}</span>
                    <span className="cat-item-meta">
                      Meta Atual: <strong>{formatCurrency(meta?.valor_meta)}</strong>
                    </span>
                  </div>
                </div>
                <Edit2 size={16} className="cat-edit-icon" />
              </div>
            );
          })
        ) : (
          <div className="cat-empty">Nenhuma categoria em "{activeTab === 'despesa' ? 'Saídas' : 'Entradas'}".</div>
        )}
      </div>
    </div>
  );
};

export default Categorias;
